const dcQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es el nombre kryptoniano de Superman?",o:["Kal-El", "Jor-El", "Zod-El", "Kon-El"],a:0,exp:"El nombre kryptoniano de Superman es Kal-El. Sus padres biol\u00f3gicos son Jor-El y Lara Lor-Van, quienes lo env\u00edan a la Tierra antes de la destrucci\u00f3n de Krypton.",extra:"El contraste entre Kal-El y Clark Kent es central en Superman: uno es su herencia alien\u00edgena y el otro su crianza humana en Smallville. La grandeza del personaje nace justamente de esa doble identidad: poder casi divino, pero valores profundamente humanos."},
  {t:"m",q:"\u00bfEn qu\u00e9 ciudad opera principalmente Batman?",o:["Metr\u00f3polis", "Gotham City", "Central City", "Star City"],a:1,exp:"Batman protege Gotham City, una ciudad oscura, corrupta y g\u00f3tica que refleja muchos de los temas centrales del personaje.",extra:"Gotham no es solo un escenario: funciona casi como un personaje. Su crimen organizado, arquitectura opresiva y corrupci\u00f3n institucional explican por qu\u00e9 Batman se convierte en una figura de miedo para los criminales."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre civil de Wonder Woman?",o:["Diana Prince", "Donna Troy", "Barbara Minerva", "Hippolyta Trevor"],a:0,exp:"Wonder Woman usa el nombre civil Diana Prince en el mundo de los humanos.",extra:"Diana es princesa de Themyscira, hija de la reina Hip\u00f3lita. En muchas versiones modernas, su origen est\u00e1 ligado tambi\u00e9n a los dioses griegos, lo que la conecta con mitolog\u00eda, diplomacia y guerra."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre civil de Barry Allen?",o:["Wally West", "Jay Garrick", "Barry Allen", "Bart Allen"],a:2,exp:"Barry Allen es uno de los personajes m\u00e1s famosos en portar el manto de Flash.",extra:"Barry es un cient\u00edfico forense que obtiene supervelocidad tras un accidente con qu\u00edmicos y un rayo. Su conexi\u00f3n con la Speed Force lo convierte en una figura clave del multiverso DC."},
  {t:"m",q:"\u00bfQu\u00e9 villano es conocido como el archienemigo principal de Superman?",o:["Darkseid", "Lex Luthor", "Brainiac", "Metallo"],a:1,exp:"Lex Luthor es el enemigo m\u00e1s ic\u00f3nico de Superman, un genio humano obsesionado con demostrar que el Hombre de Acero es una amenaza.",extra:"La rivalidad entre Superman y Luthor funciona porque no depende solo de fuerza f\u00edsica. Luthor odia lo que Superman representa: esperanza, humildad y poder usado sin ambici\u00f3n personal."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman suele representarse como un payaso criminal?",o:["Dos Caras", "El Acertijo", "El Joker", "Espantap\u00e1jaros"],a:2,exp:"El Joker es el payaso criminal de Gotham y el enemigo m\u00e1s famoso de Batman.",extra:"El Joker representa el caos frente al orden obsesivo de Batman. Su origen cambia seg\u00fan la versi\u00f3n, pero su papel casi siempre es el mismo: probar los l\u00edmites morales del Caballero Oscuro."},
  {t:"m",q:"\u00bfCu\u00e1l es la isla natal de Wonder Woman?",o:["Atlantis", "Themyscira", "Kahndaq", "Nanda Parbat"],a:1,exp:"Wonder Woman proviene de Themyscira, la isla oculta de las amazonas.",extra:"Themyscira es una sociedad de guerreras inmortales creada bajo la protecci\u00f3n de los dioses. Su aislamiento del mundo exterior es clave para entender el choque cultural de Diana al llegar al mundo humano."},
  {t:"m",q:"\u00bfQu\u00e9 objeto suele usar Green Lantern para crear construcciones de energ\u00eda?",o:["Un casco m\u00e1gico", "Un anillo de poder", "Una piedra madre", "Un tridente"],a:1,exp:"Los Green Lanterns usan anillos de poder alimentados por la fuerza de voluntad.",extra:"El anillo de Green Lantern puede crear casi cualquier forma que su portador imagine, siempre que tenga suficiente voluntad y concentraci\u00f3n. Por eso el arma refleja directamente la mente del h\u00e9roe."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre civil de Aquaman?",o:["Arthur Curry", "Orin Blake", "Jackson Hyde", "Thomas Curry"],a:0,exp:"Aquaman es Arthur Curry, heredero de Atlantis y del mundo de la superficie.",extra:"Arthur vive entre dos mundos: el oc\u00e9ano y la tierra. Esa dualidad lo convierte en rey, guerrero y diplom\u00e1tico, aunque durante a\u00f1os fue injustamente subestimado fuera de los c\u00f3mics."},
  {t:"m",q:"\u00bfQu\u00e9 equipo re\u00fane tradicionalmente a h\u00e9roes como Superman, Batman, Wonder Woman, Flash, Aquaman y Green Lantern?",o:["La Sociedad de la Justicia", "La Liga de la Justicia", "Los J\u00f3venes Titanes", "La Patrulla Condenada"],a:1,exp:"La Liga de la Justicia es el equipo insignia de superh\u00e9roes de DC Comics.",extra:"La Liga funciona como el equivalente mitol\u00f3gico moderno de un pante\u00f3n: h\u00e9roes con poderes enormes, personalidades muy distintas y responsabilidades que suelen afectar al planeta entero o al multiverso."},
  {t:"m",q:"\u00bfCu\u00e1l es el planeta natal de Superman?",o:["Apokolips", "Krypton", "Rann", "Thanagar"],a:1,exp:"Superman naci\u00f3 en Krypton, un planeta avanzado que fue destruido poco despu\u00e9s de su nacimiento.",extra:"La destrucci\u00f3n de Krypton marca a Superman como \u00faltimo hijo de una civilizaci\u00f3n perdida. Ese elemento de inmigrante, sobreviviente y heredero de una cultura extinta da profundidad emocional al personaje."},
  {t:"m",q:"\u00bfQui\u00e9n cr\u00eda a Superman en la Tierra?",o:["Thomas y Martha Wayne", "Jonathan y Martha Kent", "Jor-El y Lara", "Perry y Alice White"],a:1,exp:"Jonathan y Martha Kent encuentran al beb\u00e9 Kal-El y lo cr\u00edan como Clark Kent en Smallville.",extra:"Los Kent son fundamentales porque ense\u00f1an a Clark compasi\u00f3n, responsabilidad y humildad. Sin ellos, Superman podr\u00eda ser solo un ser poderoso; con ellos, se convierte en h\u00e9roe."},
  {t:"m",q:"\u00bfQu\u00e9 evento traum\u00e1tico impulsa a Bruce Wayne a convertirse en Batman?",o:["La destrucci\u00f3n de su planeta", "El asesinato de sus padres", "La p\u00e9rdida de sus poderes", "Una invasi\u00f3n alien\u00edgena"],a:1,exp:"Bruce Wayne decide combatir el crimen despu\u00e9s de presenciar el asesinato de sus padres, Thomas y Martha Wayne.",extra:"Ese trauma define su misi\u00f3n, pero tambi\u00e9n su obsesi\u00f3n. Batman intenta transformar una tragedia personal en una guerra contra el miedo, el crimen y la corrupci\u00f3n."},
  {t:"m",q:"\u00bfQui\u00e9n es el mayordomo y figura paterna de Bruce Wayne?",o:["Lucius Fox", "Alfred Pennyworth", "Jim Gordon", "Harvey Bullock"],a:1,exp:"Alfred Pennyworth es el mayordomo de la familia Wayne y una de las figuras emocionales m\u00e1s importantes para Bruce.",extra:"Alfred no solo cuida la mansi\u00f3n. Es m\u00e9dico, confidente, conciencia moral y padre sustituto. En muchas historias, es la persona que m\u00e1s claramente ve el costo humano de ser Batman."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman est\u00e1 obsesionado con acertijos y juegos mentales?",o:["Bane", "El Acertijo", "Hiedra Venenosa", "Clayface"],a:1,exp:"El Acertijo, o Riddler, comete cr\u00edmenes dejando pistas, juegos de l\u00f3gica y enigmas para Batman.",extra:"El Acertijo representa el desaf\u00edo intelectual de Batman. No busca solo dinero o poder: necesita demostrar que es m\u00e1s inteligente que el detective m\u00e1s famoso de Gotham."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre real de Catwoman?",o:["Selina Kyle", "Pamela Isley", "Harleen Quinzel", "Dinah Lance"],a:0,exp:"Catwoman es Selina Kyle, ladrona experta y una de las figuras m\u00e1s ambiguas en la vida de Batman.",extra:"Selina no encaja del todo como villana ni como hero\u00edna. Su relaci\u00f3n con Batman mezcla atracci\u00f3n, rivalidad, \u00e9tica propia y una comprensi\u00f3n \u00edntima de la vida nocturna de Gotham."},
  {t:"m",q:"\u00bfQu\u00e9 villana de Batman era originalmente la psiquiatra Harleen Quinzel?",o:["Hiedra Venenosa", "Harley Quinn", "Talia al Ghul", "Lady Shiva"],a:1,exp:"Harley Quinn era la doctora Harleen Quinzel antes de ser manipulada por el Joker y adoptar una identidad criminal.",extra:"Harley naci\u00f3 en Batman: The Animated Series y luego pas\u00f3 a los c\u00f3mics. Con el tiempo evolucion\u00f3 de acompa\u00f1ante del Joker a personaje independiente, ca\u00f3tica y muchas veces antiheroica."},
  {t:"m",q:"\u00bfQu\u00e9 villano rompi\u00f3 la espalda de Batman en la saga Knightfall?",o:["Ra\u2019s al Ghul", "Bane", "Deathstroke", "Killer Croc"],a:1,exp:"Bane derrota f\u00edsicamente a Batman y le rompe la espalda durante Knightfall.",extra:"Bane no es solo fuerza bruta. Su peligro viene de combinar inteligencia estrat\u00e9gica, paciencia y poder f\u00edsico aumentado por Venom. Por eso su victoria sobre Batman fue tan impactante."},
  {t:"m",q:"\u00bfQu\u00e9 enemigo de Superman es una inteligencia alien\u00edgena obsesionada con recolectar y reducir ciudades?",o:["Brainiac", "Mongul", "Parasite", "Doomsday"],a:0,exp:"Brainiac es una inteligencia alien\u00edgena que colecciona conocimiento y ciudades, incluida Kandor en muchas versiones.",extra:"Brainiac funciona como una amenaza fr\u00eda y c\u00f3smica: no destruye por rabia, sino por una l\u00f3gica de preservaci\u00f3n retorcida. Para Superman, tambi\u00e9n representa la p\u00e9rdida de Krypton convertida en museo viviente."},
  {t:"m",q:"\u00bfQu\u00e9 criatura mat\u00f3 a Superman en la famosa saga The Death of Superman?",o:["Darkseid", "Doomsday", "General Zod", "Lobo"],a:1,exp:"Doomsday es la criatura que mata a Superman en una batalla brutal en The Death of Superman.",extra:"La muerte de Superman en los a\u00f1os 90 fue un evento enorme en la cultura pop. Doomsday no era un villano complejo: era una fuerza imparable dise\u00f1ada para mostrar que incluso Superman pod\u00eda caer."},
  {t:"m",q:"\u00bfQu\u00e9 villano kryptoniano suele exigir que otros se arrodillen ante \u00e9l?",o:["Jor-El", "General Zod", "Mon-El", "Eradicator"],a:1,exp:"El General Zod es un militar kryptoniano enemigo de Superman y famoso por su arrogancia autoritaria.",extra:"Zod es especialmente peligroso porque comparte poderes similares a Superman bajo el sol amarillo, pero carece de su compasi\u00f3n. Representa lo que Kal-El podr\u00eda ser sin la crianza de los Kent."},
  {t:"m",q:"\u00bfCu\u00e1l es la debilidad m\u00e1s famosa de Superman?",o:["El agua", "La kryptonita", "La plata", "El fuego"],a:1,exp:"La kryptonita es el mineral radiactivo de Krypton que debilita a Superman.",extra:"La kryptonita permite que historias de Superman tengan vulnerabilidad f\u00edsica. Tambi\u00e9n hay variantes de colores con efectos distintos seg\u00fan la continuidad, como roja, dorada o azul."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es conocido como el primer Robin?",o:["Jason Todd", "Tim Drake", "Dick Grayson", "Damian Wayne"],a:2,exp:"Dick Grayson fue el primer Robin, compa\u00f1ero juvenil de Batman.",extra:"Dick creci\u00f3 hasta convertirse en Nightwing, uno de los h\u00e9roes m\u00e1s respetados de DC. Su evoluci\u00f3n muestra que Batman puede inspirar algo m\u00e1s sano que su propia obsesi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 Robin fue asesinado por el Joker y luego regres\u00f3 como Red Hood?",o:["Tim Drake", "Jason Todd", "Damian Wayne", "Duke Thomas"],a:1,exp:"Jason Todd, el segundo Robin, fue asesinado por el Joker y volvi\u00f3 a\u00f1os despu\u00e9s como Red Hood.",extra:"El regreso de Jason confronta a Batman con una pregunta dolorosa: si su c\u00f3digo de no matar realmente protege Gotham o permite que monstruos como el Joker sigan destruyendo vidas."},
  {t:"m",q:"\u00bfQui\u00e9n es el padre biol\u00f3gico de Damian Wayne?",o:["Dick Grayson", "Bruce Wayne", "Ra\u2019s al Ghul", "Slade Wilson"],a:1,exp:"Damian Wayne es hijo biol\u00f3gico de Bruce Wayne y Talia al Ghul.",extra:"Damian fue criado por la Liga de Asesinos, lo que lo convierte en un Robin arrogante, letal y dif\u00edcil de educar. Su arco consiste en aprender empat\u00eda sin perder su disciplina."},
  {t:"m",q:"\u00bfQu\u00e9 comisionado de polic\u00eda es el aliado m\u00e1s famoso de Batman?",o:["Harvey Bullock", "Jim Gordon", "Renee Montoya", "Crispus Allen"],a:1,exp:"Jim Gordon es el comisionado de Gotham y uno de los aliados m\u00e1s importantes de Batman.",extra:"Gordon representa la posibilidad de justicia dentro del sistema. Su relaci\u00f3n con Batman es una alianza inc\u00f3moda pero necesaria entre ley formal y vigilancia nocturna."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre real de Two-Face?",o:["Harvey Dent", "Edward Nygma", "Victor Fries", "Roman Sionis"],a:0,exp:"Two-Face es Harvey Dent, antiguo fiscal de distrito de Gotham.",extra:"La tragedia de Harvey Dent funciona porque era una esperanza real para Gotham. Su transformaci\u00f3n en Two-Face convierte la justicia en azar, simbolizado por su moneda marcada."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman usa toxinas del miedo?",o:["Espantap\u00e1jaros", "Mr. Freeze", "Black Mask", "Profesor Pyg"],a:0,exp:"El Espantap\u00e1jaros, Jonathan Crane, usa toxinas para inducir miedo extremo en sus v\u00edctimas.",extra:"Scarecrow es un enemigo perfecto para Batman porque ambos entienden el miedo como herramienta. La diferencia es que Batman intenta dirigirlo contra criminales, mientras Crane lo estudia y disfruta como experimento."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre real de Poison Ivy?",o:["Pamela Isley", "Selina Kyle", "Harleen Quinzel", "Zatanna Zatara"],a:0,exp:"Poison Ivy es Pamela Isley, una eco-terrorista con control sobre plantas y toxinas.",extra:"Ivy ha evolucionado mucho con el tiempo. De villana seductora pas\u00f3 a figura compleja, ligada a ecolog\u00eda radical, trauma, independencia y su v\u00ednculo con Harley Quinn."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman necesita un traje criog\u00e9nico para sobrevivir?",o:["Clayface", "Mr. Freeze", "Killer Croc", "Hush"],a:1,exp:"Mr. Freeze, Victor Fries, necesita temperaturas extremadamente bajas para vivir.",extra:"La versi\u00f3n m\u00e1s famosa de Mr. Freeze se consolid\u00f3 en Batman: The Animated Series, donde su tragedia con Nora Fries lo convirti\u00f3 en uno de los villanos m\u00e1s emocionalmente potentes de Gotham."},
  {t:"m",q:"\u00bfQu\u00e9 villano c\u00f3smico de DC gobierna Apokolips?",o:["Mongul", "Darkseid", "Despero", "Nekron"],a:1,exp:"Darkseid gobierna Apokolips y busca dominar toda voluntad mediante la Ecuaci\u00f3n Anti-Vida.",extra:"Darkseid no es solo un conquistador espacial. Es una encarnaci\u00f3n del totalitarismo c\u00f3smico: quiere eliminar la libertad interior de todos los seres."},
  {t:"m",q:"\u00bfCu\u00e1l es el objetivo obsesivo de Darkseid?",o:["Encontrar la Ecuaci\u00f3n Anti-Vida", "Destruir la kryptonita", "Conquistar Atlantis", "Crear nuevos Lanterns"],a:0,exp:"Darkseid busca la Ecuaci\u00f3n Anti-Vida, una f\u00f3rmula que le permitir\u00eda dominar la voluntad de los seres vivos.",extra:"La Ecuaci\u00f3n Anti-Vida es una de las ideas m\u00e1s aterradoras de DC porque no trata solo de matar o conquistar, sino de borrar la libertad y la esperanza."},
  {t:"m",q:"\u00bfQu\u00e9 amazona es madre de Diana en la mayor\u00eda de versiones?",o:["Ant\u00edope", "Hip\u00f3lita", "Artemisa", "Nubia"],a:1,exp:"La reina Hip\u00f3lita es la madre de Diana y gobernante de las amazonas de Themyscira.",extra:"Hip\u00f3lita representa tradici\u00f3n, protecci\u00f3n y autoridad. Su relaci\u00f3n con Diana suele tensarse cuando la princesa decide abandonar la isla para ayudar al mundo exterior."},
  {t:"m",q:"\u00bfQu\u00e9 villana de Wonder Woman suele transformarse en Cheetah?",o:["Barbara Minerva", "Circe", "Veronica Cale", "Giganta"],a:0,exp:"Barbara Minerva es una de las versiones m\u00e1s conocidas de Cheetah, enemiga de Wonder Woman.",extra:"Cheetah funciona como espejo oscuro de Diana: una mujer brillante y ambiciosa consumida por maldiciones, celos o deseo de poder, seg\u00fan la continuidad."},
  {t:"m",q:"\u00bfQu\u00e9 lazo m\u00e1gico usa Wonder Woman?",o:["El Lazo de la Verdad", "El Lazo de Apokolips", "El Cord\u00f3n de Hermes", "La Cadena de H\u00e9cate"],a:0,exp:"Wonder Woman usa el Lazo de la Verdad, que obliga a quienes quedan atrapados a decir la verdad.",extra:"El lazo es m\u00e1s que un arma: representa la filosof\u00eda de Diana. Su poder no se basa solo en vencer, sino en revelar, comprender y confrontar la verdad."},
  {t:"m",q:"\u00bfQu\u00e9 dios de la guerra es uno de los enemigos cl\u00e1sicos de Wonder Woman?",o:["Ares", "Hermes", "Poseid\u00f3n", "Apolo"],a:0,exp:"Ares, dios de la guerra, es uno de los enemigos mitol\u00f3gicos m\u00e1s importantes de Wonder Woman.",extra:"Ares encarna la violencia, el conflicto y la corrupci\u00f3n b\u00e9lica del mundo humano. Su enfrentamiento con Diana suele ser tanto f\u00edsico como ideol\u00f3gico."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad protege principalmente Barry Allen como Flash?",o:["Gotham City", "Central City", "Metr\u00f3polis", "Coast City"],a:1,exp:"Barry Allen opera principalmente en Central City.",extra:"Central City tiene un tono distinto a Gotham o Metr\u00f3polis: suele estar marcada por ciencia extra\u00f1a, villanos coloridos y fen\u00f3menos relacionados con la Speed Force."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la fuerza extradimensional que da poder a muchos velocistas de DC?",o:["Speed Force", "Quantum Web", "Fuente Alfa", "Energ\u00eda Omega"],a:0,exp:"La Speed Force es la fuente de poder de Flash y otros velocistas.",extra:"La Speed Force permite velocidad sobrehumana, viajes en el tiempo, vibraci\u00f3n molecular y haza\u00f1as que rozan lo c\u00f3smico. Tambi\u00e9n es una de las herramientas narrativas m\u00e1s importantes del multiverso DC."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Flash viaja en el tiempo y suele usar un traje amarillo?",o:["Captain Cold", "Gorilla Grodd", "Reverse-Flash", "Mirror Master"],a:2,exp:"Reverse-Flash, especialmente Eobard Thawne, es el enemigo temporal m\u00e1s famoso de Barry Allen.",extra:"Reverse-Flash odia a Barry de manera obsesiva y personal. Su habilidad de alterar el pasado lo convierte en uno de los villanos m\u00e1s crueles de DC."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre de la esposa o gran amor de Barry Allen en muchas historias?",o:["Iris West", "Linda Park", "Lois Lane", "Carol Ferris"],a:0,exp:"Iris West es el gran amor de Barry Allen y una figura central en el mundo de Flash.",extra:"La familia West es esencial para el legado de Flash. A trav\u00e9s de Iris, Wally West y otros personajes, Flash se convierte en una historia de familia, mentor\u00eda y herencia heroica."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Flash lidera o integra frecuentemente a los Rogues usando una pistola de fr\u00edo?",o:["Captain Cold", "Heat Wave", "Weather Wizard", "Pied Piper"],a:0,exp:"Captain Cold, Leonard Snart, usa una pistola de fr\u00edo y es uno de los l\u00edderes m\u00e1s importantes de los Rogues.",extra:"Los Rogues son distintos a muchos villanos: tienen c\u00f3digos internos, reglas y una din\u00e1mica casi laboral. Captain Cold suele actuar como criminal profesional m\u00e1s que como monstruo ca\u00f3tico."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe de DC es conocido por usar arco y flechas en Star City?",o:["Green Arrow", "Hawkman", "Red Tornado", "Blue Beetle"],a:0,exp:"Green Arrow, Oliver Queen, es el arquero vigilante asociado principalmente con Star City.",extra:"Green Arrow suele representar una conciencia social m\u00e1s directa dentro de DC. Muchas historias lo muestran enfrentando corrupci\u00f3n, desigualdad y problemas urbanos desde una mirada pol\u00edtica."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre civil de Green Arrow?",o:["Hal Jordan", "Oliver Queen", "Ray Palmer", "Ted Kord"],a:1,exp:"Green Arrow es Oliver Queen, un millonario convertido en vigilante arquero.",extra:"Oliver comparte ciertos paralelos con Batman, pero su personalidad es m\u00e1s impulsiva, sarc\u00e1stica y pol\u00edticamente combativa. Su arco cl\u00e1sico implica perder privilegios y reconstruirse con una misi\u00f3n social."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe de DC es piloto de pruebas y uno de los Green Lanterns m\u00e1s famosos?",o:["Hal Jordan", "John Stewart", "Guy Gardner", "Kyle Rayner"],a:0,exp:"Hal Jordan es piloto de pruebas y uno de los portadores m\u00e1s conocidos del anillo de Green Lantern.",extra:"Hal fue elegido por su capacidad de superar el miedo. Su car\u00e1cter impulsivo y valiente lo convierte en un Lantern poderoso, aunque tambi\u00e9n lo ha llevado a ca\u00eddas importantes."},
  {t:"m",q:"\u00bfQu\u00e9 Green Lantern humano es tambi\u00e9n arquitecto y ex marine?",o:["Kyle Rayner", "John Stewart", "Alan Scott", "Simon Baz"],a:1,exp:"John Stewart es arquitecto y ex marine, conocido por su disciplina y precisi\u00f3n como Green Lantern.",extra:"John gan\u00f3 enorme popularidad gracias a la serie animada Justice League. Su forma de crear construcciones suele reflejar su mente de arquitecto: estructuras s\u00f3lidas, funcionales y detalladas."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Green Lantern usa un anillo amarillo alimentado por el miedo?",o:["Sinestro", "Atrocitus", "Black Hand", "Larfleeze"],a:0,exp:"Sinestro fue Green Lantern antes de convertirse en l\u00edder de los Yellow Lanterns, alimentados por el miedo.",extra:"Sinestro es fascinante porque cree en el orden por encima de la libertad. Su ca\u00edda no nace de la simple maldad, sino de una convicci\u00f3n autoritaria: controlar para evitar el caos."},
  {t:"m",q:"\u00bfQu\u00e9 reino submarino gobierna Aquaman?",o:["Atlantis", "Xebel", "Poseidonis Prime", "Skartaris"],a:0,exp:"Aquaman es rey de Atlantis, uno de los reinos submarinos m\u00e1s importantes de DC.",extra:"Atlantis en DC combina fantas\u00eda, pol\u00edtica, tecnolog\u00eda antigua y conflictos de sucesi\u00f3n. Arthur suele quedar atrapado entre sus deberes como rey y su identidad como h\u00e9roe global."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Aquaman usa casco negro y guarda un profundo odio personal contra Arthur Curry?",o:["Ocean Master", "Black Manta", "King Shark", "The Trench King"],a:1,exp:"Black Manta es uno de los enemigos m\u00e1s ic\u00f3nicos de Aquaman y suele tener una rivalidad profundamente personal con \u00e9l.",extra:"Black Manta destaca por su dise\u00f1o visual y por el car\u00e1cter obsesivo de su odio. En muchas versiones, su conflicto con Arthur est\u00e1 marcado por tragedias familiares y venganza."},
  {t:"m",q:"\u00bfQui\u00e9n es Orm dentro del mundo de Aquaman?",o:["Su hermano y rival, Ocean Master", "Un general de Apokolips", "Un rey de Gorilla City", "Un Linterna Rojo"],a:0,exp:"Orm, tambi\u00e9n conocido como Ocean Master, suele ser medio hermano de Aquaman y rival por el trono de Atlantis.",extra:"Orm representa el lado m\u00e1s aislacionista y agresivo de Atlantis. Su conflicto con Arthur es familiar, pol\u00edtico y cultural al mismo tiempo."},
  {t:"m",q:"\u00bfQu\u00e9 grupo juvenil de h\u00e9roes incluye tradicionalmente a Robin, Starfire, Raven, Cyborg y Beast Boy?",o:["La Liga de la Justicia Oscura", "Los J\u00f3venes Titanes", "La Legi\u00f3n de Superh\u00e9roes", "Los Outsiders"],a:1,exp:"Los J\u00f3venes Titanes son el equipo juvenil m\u00e1s famoso de DC.",extra:"Los Titanes funcionan especialmente bien porque mezclan acci\u00f3n superheroica con crecimiento personal. Muchas de sus historias tratan sobre identidad, amistad y formar una familia elegida."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre civil de Cyborg?",o:["Victor Stone", "Virgil Hawkins", "Jefferson Pierce", "Michael Holt"],a:0,exp:"Cyborg es Victor Stone, un joven reconstruido con tecnolog\u00eda avanzada tras un accidente terrible.",extra:"Cyborg explora temas de cuerpo, humanidad, trauma y tecnolog\u00eda. En algunas continuidades es Tit\u00e1n fundador; en otras, miembro central de la Liga de la Justicia."},
  {t:"m",q:"\u00bfQu\u00e9 hero\u00edna de los Titanes es una princesa alien\u00edgena de Tamaran?",o:["Raven", "Starfire", "Donna Troy", "Bumblebee"],a:1,exp:"Starfire, o Koriand r, es una princesa de Tamaran con poderes solares y gran fuerza f\u00edsica.",extra:"Starfire aporta al equipo una mezcla de inocencia cultural, poder enorme y emotividad directa. Su forma de expresar afecto contrasta con personajes m\u00e1s cerrados como Raven o Robin."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Titanes es hija del demonio Trigon?",o:["Raven", "Terra", "Starfire", "Wonder Girl"],a:0,exp:"Raven es hija de Trigon y debe controlar constantemente sus emociones para evitar su influencia demon\u00edaca.",extra:"Raven es uno de los personajes m\u00e1s potentes de los Titanes porque su conflicto es interno y c\u00f3smico a la vez. Su calma no es frialdad: es disciplina para contener algo terrible."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe de DC puede transformarse en animales?",o:["Beast Boy", "Plastic Man", "Animal Man", "Metamorpho"],a:0,exp:"Beast Boy puede transformarse en animales, manteniendo normalmente su caracter\u00edstico color verde.",extra:"Aunque suele ser el alivio c\u00f3mico de los Titanes, Beast Boy tiene historias muy tr\u00e1gicas. Su humor funciona muchas veces como defensa ante p\u00e9rdidas y traumas."},
  {t:"m",q:"\u00bfQu\u00e9 hechicera de DC suele lanzar conjuros diciendo las palabras al rev\u00e9s?",o:["Zatanna", "Enchantress", "Raven", "Madame Xanadu"],a:0,exp:"Zatanna Zatara usa magia pronunciando palabras al rev\u00e9s.",extra:"Zatanna conecta el mundo superheroico con el lado m\u00e1gico de DC. Su herencia familiar, su carrera como maga esc\u00e9nica y su poder real la vuelven una figura muy singular."},
  {t:"m",q:"\u00bfQu\u00e9 equipo de DC se especializa en amenazas sobrenaturales y m\u00e1gicas?",o:["Justice League Dark", "Checkmate", "Suicide Squad", "Metal Men"],a:0,exp:"Justice League Dark re\u00fane h\u00e9roes m\u00e1gicos y sobrenaturales para enfrentar amenazas que la Liga tradicional no puede resolver f\u00e1cilmente.",extra:"El equipo suele incluir personajes como John Constantine, Zatanna, Deadman, Swamp Thing y otros especialistas en ocultismo, maldiciones y dimensiones extra\u00f1as."},
  {t:"m",q:"\u00bfQu\u00e9 antih\u00e9roe brit\u00e1nico de DC es famoso por su gabardina, cigarrillos y magia peligrosa?",o:["John Constantine", "Jason Blood", "Boston Brand", "Etrigan"],a:0,exp:"John Constantine es un ocultista brit\u00e1nico conocido por resolver problemas m\u00e1gicos mediante enga\u00f1os, sacrificios y decisiones moralmente grises.",extra:"Constantine rara vez gana sin perder algo. Su encanto viene de ser brillante y miserable a la vez: salva el mundo, pero suele destruir sus relaciones en el proceso."},
  {t:"m",q:"\u00bfQu\u00e9 criatura elemental de DC est\u00e1 conectada al Verde?",o:["Swamp Thing", "Solomon Grundy", "Man-Bat", "Etrigan"],a:0,exp:"Swamp Thing est\u00e1 conectado al Verde, una fuerza elemental relacionada con toda la vida vegetal.",extra:"Swamp Thing pas\u00f3 de ser un monstruo tr\u00e1gico a una de las figuras m\u00e1s filos\u00f3ficas de DC, especialmente en etapas como la de Alan Moore, donde se explora identidad, naturaleza y conciencia."},
  {t:"m",q:"\u00bfQu\u00e9 villano inmortal suele ser enemigo de la Liga y ha vivido desde tiempos antiguos?",o:["Vandal Savage", "Maxwell Lord", "Hugo Strange", "Prometheus"],a:0,exp:"Vandal Savage es un inmortal que ha influido en la historia humana durante miles de a\u00f1os.",extra:"Su amenaza no depende solo de poderes f\u00edsicos, sino de experiencia, paciencia y acumulaci\u00f3n de poder. Puede perder una batalla y seguir planeando durante siglos."},
  {t:"m",q:"\u00bfQu\u00e9 equipo gubernamental obliga a villanos a realizar misiones peligrosas?",o:["Suicide Squad", "Doom Patrol", "Secret Six", "Outsiders"],a:0,exp:"Suicide Squad, o Task Force X, usa criminales encarcelados para misiones encubiertas de alt\u00edsimo riesgo.",extra:"La idea central del Escuadr\u00f3n Suicida es brutal: villanos prescindibles enviados a tareas que el gobierno negar\u00eda p\u00fablicamente. Amanda Waller es la figura clave detr\u00e1s del programa."},
  {t:"m",q:"\u00bfQui\u00e9n dirige habitualmente al Suicide Squad desde las sombras?",o:["Amanda Waller", "Lois Lane", "Barbara Gordon", "Talia al Ghul"],a:0,exp:"Amanda Waller dirige Task Force X con m\u00e9todos fr\u00edos, pragm\u00e1ticos y muchas veces despiadados.",extra:"Waller es peligrosa porque no necesita superpoderes. Su fuerza est\u00e1 en informaci\u00f3n, autoridad, manipulaci\u00f3n y una voluntad casi inquebrantable."},
  {t:"m",q:"\u00bfQu\u00e9 identidad superheroica adopta Dick Grayson despu\u00e9s de dejar de ser Robin?",o:["Red Hood", "Nightwing", "Red Robin", "Azrael"],a:1,exp:"Dick Grayson adopta la identidad de Nightwing tras independizarse de Batman.",extra:"Nightwing representa el crecimiento sano del legado de Batman. Dick conserva la disciplina y el sentido de justicia de Bruce, pero a\u00f1ade calidez, liderazgo y una relaci\u00f3n menos obsesiva con la misi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad protege principalmente Nightwing?",o:["Bl\u00fcdhaven", "Gotham City", "Central City", "Hub City"],a:0,exp:"Nightwing opera principalmente en Bl\u00fcdhaven, una ciudad cercana a Gotham con su propia corrupci\u00f3n y crimen organizado.",extra:"Bl\u00fcdhaven le permite a Dick Grayson construir una identidad heroica independiente. Aunque comparte ra\u00edces con Batman, su manera de proteger la ciudad suele ser m\u00e1s abierta y cercana a la comunidad."},
  {t:"m",q:"\u00bfQui\u00e9n fue Barbara Gordon originalmente dentro de la Bat-familia?",o:["Batwoman", "Batgirl", "Spoiler", "Huntress"],a:1,exp:"Barbara Gordon fue una de las Batgirls m\u00e1s importantes de DC Comics.",extra:"Barbara es hija de Jim Gordon y una de las mentes m\u00e1s brillantes de Gotham. Su evoluci\u00f3n posterior como Oracle la convirti\u00f3 en una figura clave de inteligencia, coordinaci\u00f3n y accesibilidad dentro del universo DC."},
  {t:"m",q:"\u00bfQu\u00e9 identidad adopta Barbara Gordon tras quedar paralizada en muchas continuidades cl\u00e1sicas?",o:["Oracle", "Black Canary", "Question", "Lady Blackhawk"],a:0,exp:"Barbara Gordon adopta la identidad de Oracle despu\u00e9s de quedar paralizada por un ataque del Joker en The Killing Joke.",extra:"Como Oracle, Barbara demuestra que su hero\u00edsmo no depend\u00eda solo del combate f\u00edsico. Se convierte en una estratega, hacker y coordinadora central para h\u00e9roes de todo el mundo."},
  {t:"m",q:"\u00bfQu\u00e9 grupo de hero\u00ednas fue fundado o liderado frecuentemente por Oracle y Black Canary?",o:["Birds of Prey", "Secret Six", "Female Furies", "Doom Patrol"],a:0,exp:"Birds of Prey es un equipo asociado especialmente con Oracle y Black Canary.",extra:"Birds of Prey destaca por combinar espionaje, acci\u00f3n urbana y relaciones entre hero\u00ednas. Es uno de los grupos m\u00e1s importantes de DC fuera de la Liga de la Justicia."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre real de Black Canary m\u00e1s conocido en la continuidad moderna?",o:["Dinah Lance", "Helena Bertinelli", "Kate Kane", "Renee Montoya"],a:0,exp:"Black Canary suele ser Dinah Lance, una experta luchadora con un poderoso grito s\u00f3nico.",extra:"Dinah combina artes marciales, actitud callejera y una voz capaz de destruir estructuras. Su relaci\u00f3n con Green Arrow es una de las parejas cl\u00e1sicas de DC."},
  {t:"m",q:"\u00bfQu\u00e9 hero\u00edna de Gotham es conocida como Huntress en muchas historias?",o:["Helena Bertinelli", "Stephanie Brown", "Cassandra Cain", "Kathy Kane"],a:0,exp:"Helena Bertinelli es una de las versiones m\u00e1s conocidas de Huntress.",extra:"Huntress suele tener v\u00ednculos con familias mafiosas de Gotham, lo que la coloca en una zona moral m\u00e1s dura que otros miembros de la Bat-familia. Su violencia genera tensiones con Batman."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es hijo de Batman y Talia al Ghul?",o:["Tim Drake", "Damian Wayne", "Jason Todd", "Terry McGinnis"],a:1,exp:"Damian Wayne es hijo biol\u00f3gico de Bruce Wayne y Talia al Ghul.",extra:"Damian fue criado por la Liga de Asesinos, por eso llega a la Bat-familia con habilidades letales y una moralidad muy distinta. Su desarrollo consiste en aprender compasi\u00f3n sin perder disciplina."},
  {t:"m",q:"\u00bfQu\u00e9 villano lidera la Liga de Asesinos?",o:["Ra\u2019s al Ghul", "Bane", "Deathstroke", "Black Mask"],a:0,exp:"Ra\u2019s al Ghul es el l\u00edder de la Liga de Asesinos y uno de los enemigos m\u00e1s peligrosos de Batman.",extra:"Ra\u2019s no se ve a s\u00ed mismo como criminal com\u00fan. Cree que sus m\u00e9todos extremos son necesarios para salvar el planeta de la corrupci\u00f3n humana, lo que lo vuelve un rival ideol\u00f3gico de Batman."},
  {t:"m",q:"\u00bfQu\u00e9 pozo permite a Ra\u2019s al Ghul prolongar su vida?",o:["Pozo de L\u00e1zaro", "Pozo del Destino", "Fuente de Metr\u00f3n", "Piscina de Apokolips"],a:0,exp:"Los Pozos de L\u00e1zaro restauran la vida y juventud de Ra\u2019s al Ghul, aunque con efectos secundarios mentales.",extra:"Los Pozos de L\u00e1zaro introducen un elemento sobrenatural en el mundo de Batman. Tambi\u00e9n explican c\u00f3mo Ra\u2019s puede planear a escalas hist\u00f3ricas y seguir regresando."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman controla o representa frecuentemente al crimen organizado de Gotham con una m\u00e1scara negra?",o:["Roman Sionis", "Oswald Cobblepot", "Carmine Falcone", "Sal Maroni"],a:0,exp:"Black Mask es Roman Sionis, un se\u00f1or del crimen de Gotham conocido por su m\u00e1scara negra.",extra:"Black Mask representa el lado s\u00e1dico y mafioso de Gotham. A diferencia de villanos m\u00e1s teatrales, su amenaza est\u00e1 muy ligada al control callejero y la brutalidad criminal."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre real del Ping\u00fcino?",o:["Oswald Cobblepot", "Edward Nygma", "Jervis Tetch", "Basil Karlo"],a:0,exp:"El Ping\u00fcino es Oswald Cobblepot, criminal de alto perfil y due\u00f1o del Iceberg Lounge en muchas versiones.",extra:"El Ping\u00fcino funciona como puente entre el crimen organizado cl\u00e1sico y los villanos exc\u00e9ntricos de Gotham. Suele presentarse como empresario respetable mientras maneja redes criminales."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Batman est\u00e1 obsesionado con el mundo de Alicia en el Pa\u00eds de las Maravillas?",o:["Mad Hatter", "Riddler", "Professor Pyg", "Calendar Man"],a:0,exp:"Mad Hatter, Jervis Tetch, est\u00e1 obsesionado con Alicia en el Pa\u00eds de las Maravillas y el control mental.",extra:"Mad Hatter puede parecer menos f\u00edsico que otros enemigos, pero su uso de hipnosis y obsesi\u00f3n lo vuelven profundamente inquietante dentro del repertorio de Batman."},
  {t:"m",q:"\u00bfQu\u00e9 villano cambia de forma y suele estar compuesto de barro o arcilla?",o:["Clayface", "Man-Bat", "Killer Croc", "Solomon Grundy"],a:0,exp:"Clayface es el nombre usado por varios villanos con habilidades de cambio de forma y cuerpo arcilloso.",extra:"La versi\u00f3n Basil Karlo conecta la identidad de Clayface con actuaci\u00f3n, m\u00e1scara e inestabilidad personal. Es un villano ideal para historias sobre apariencia y p\u00e9rdida de identidad."},
  {t:"m",q:"\u00bfQu\u00e9 cient\u00edfico se transforma accidentalmente en Man-Bat?",o:["Kirk Langstrom", "Victor Fries", "Hugo Strange", "Jonathan Crane"],a:0,exp:"Kirk Langstrom se convierte en Man-Bat tras experimentar con un suero basado en murci\u00e9lagos.",extra:"Man-Bat invierte visualmente el s\u00edmbolo de Batman: donde Bruce usa el murci\u00e9lago como emblema de control, Langstrom se convierte literalmente en una criatura fuera de control."},
  {t:"m",q:"\u00bfQu\u00e9 periodista es el gran amor cl\u00e1sico de Superman?",o:["Lois Lane", "Lana Lang", "Cat Grant", "Iris West"],a:0,exp:"Lois Lane es la periodista del Daily Planet y el gran amor cl\u00e1sico de Superman.",extra:"Lois no es solo inter\u00e9s rom\u00e1ntico. Su valent\u00eda, inteligencia y \u00e9tica period\u00edstica la hacen una hero\u00edna por derecho propio, incluso sin poderes."},
  {t:"m",q:"\u00bfEn qu\u00e9 peri\u00f3dico trabaja Clark Kent?",o:["Daily Planet", "Gotham Gazette", "Central City Citizen", "Daily Star"],a:0,exp:"Clark Kent trabaja como periodista en el Daily Planet de Metr\u00f3polis.",extra:"El trabajo de periodista es importante porque conecta a Superman con la verdad, la vida civil y los problemas cotidianos de la gente que protege."},
  {t:"m",q:"\u00bfQui\u00e9n es el editor jefe cl\u00e1sico del Daily Planet?",o:["Perry White", "Morgan Edge", "Steve Lombard", "Ron Troupe"],a:0,exp:"Perry White es el editor jefe del Daily Planet.",extra:"Perry representa el periodismo duro, exigente y con principios. Su famosa energ\u00eda de redacci\u00f3n ayuda a sostener el mundo civil que rodea a Superman."},
  {t:"m",q:"\u00bfQu\u00e9 amigo fot\u00f3grafo de Clark Kent suele trabajar en el Daily Planet?",o:["Jimmy Olsen", "Pete Ross", "Bibbo Bibbowski", "Ronnie Raymond"],a:0,exp:"Jimmy Olsen es el amigo de Superman y fot\u00f3grafo del Daily Planet.",extra:"Jimmy ha protagonizado historias extra\u00f1\u00edsimas y muy queridas, desde transformaciones absurdas hasta aventuras c\u00f3smicas. Es una pieza importante del tono m\u00e1s luminoso del mito de Superman."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad protege Superman?",o:["Metr\u00f3polis", "Gotham City", "Star City", "Keystone City"],a:0,exp:"Superman protege principalmente Metr\u00f3polis.",extra:"Metr\u00f3polis suele representar modernidad, esperanza y progreso, en contraste con la oscuridad g\u00f3tica de Gotham. Por eso Superman y Batman se sienten tan distintos incluso compartiendo universo."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Superman est\u00e1 hecho de kryptonita o usa un coraz\u00f3n de kryptonita en varias versiones?",o:["Metallo", "Toyman", "Parasite", "Mister Mxyzptlk"],a:0,exp:"Metallo es un enemigo de Superman que suele tener un cuerpo cibern\u00e9tico alimentado por kryptonita.",extra:"Metallo es peligroso porque combina fuerza mec\u00e1nica con la debilidad principal de Superman. Adem\u00e1s, su identidad humana atrapada en m\u00e1quina lo vuelve una figura tr\u00e1gica seg\u00fan la versi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Superman puede absorber energ\u00eda y poderes?",o:["Parasite", "Livewire", "Atomic Skull", "Silver Banshee"],a:0,exp:"Parasite puede absorber energ\u00eda vital y, en muchas versiones, poderes de otros seres.",extra:"Parasite es especialmente amenazante para Superman porque convierte la cercan\u00eda f\u00edsica en un riesgo. Cuanto m\u00e1s intenta Superman detenerlo directamente, m\u00e1s puede fortalecerse."},
  {t:"m",q:"\u00bfQu\u00e9 villano extradimensional molesta a Superman con poderes casi m\u00e1gicos?",o:["Mister Mxyzptlk", "Mongul", "Ultra-Humanite", "Manchester Black"],a:0,exp:"Mister Mxyzptlk es un ser de la quinta dimensi\u00f3n que altera la realidad y suele fastidiar a Superman.",extra:"Mxyzptlk permite historias absurdas, c\u00f3micas y metanarrativas. Superman normalmente debe derrotarlo con inteligencia, no con fuerza."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad kryptoniana fue encogida y embotellada por Brainiac?",o:["Kandor", "Argo City", "Smallville", "New Genesis"],a:0,exp:"Kandor es la ciudad kryptoniana miniaturizada y conservada por Brainiac.",extra:"Kandor a\u00f1ade una capa melanc\u00f3lica al mito de Superman: no est\u00e1 completamente solo, pero su herencia existe atrapada, reducida y separada de una vida normal."},
  {t:"m",q:"\u00bfQu\u00e9 prima de Superman tambi\u00e9n sobrevivi\u00f3 a Krypton en muchas continuidades?",o:["Kara Zor-El", "Lara Lor-Van", "Lyta Trevor", "Karen Beecher"],a:0,exp:"Kara Zor-El es Supergirl, prima de Superman y superviviente de Krypton.",extra:"Supergirl suele recordar Krypton de forma m\u00e1s directa que Clark, porque en muchas versiones era mayor cuando escap\u00f3. Eso le da una relaci\u00f3n distinta con la p\u00e9rdida de su mundo."},
  {t:"m",q:"\u00bfQu\u00e9 adolescente clon relacionado con Superman usa el nombre Kon-El?",o:["Superboy", "Kid Flash", "Aqualad", "Static"],a:0,exp:"Kon-El es Superboy, un clon vinculado gen\u00e9ticamente a Superman y Lex Luthor en muchas versiones modernas.",extra:"Kon-El explora identidad y herencia desde otro \u00e1ngulo: no naci\u00f3 como Clark ni como kryptoniano tradicional, sino como experimento. Su pregunta central es qui\u00e9n decide ser."},
  {t:"m",q:"\u00bfQu\u00e9 planeta gobierna Darkseid?",o:["Apokolips", "New Genesis", "Thanagar", "Rann"],a:0,exp:"Darkseid gobierna Apokolips, un mundo infernal de f\u00e1bricas, fuego y esclavitud.",extra:"Apokolips es la expresi\u00f3n f\u00edsica del dominio de Darkseid. Todo en ese mundo comunica opresi\u00f3n, jerarqu\u00eda y destrucci\u00f3n de la individualidad."},
  {t:"m",q:"\u00bfQu\u00e9 mundo rival de Apokolips est\u00e1 asociado con los Nuevos Dioses heroicos?",o:["New Genesis", "Krypton", "Oa", "Colu"],a:0,exp:"New Genesis es el mundo luminoso asociado con Highfather y los Nuevos Dioses opuestos a Darkseid.",extra:"La oposici\u00f3n entre Apokolips y New Genesis es una de las grandes ideas de Jack Kirby en DC: tiran\u00eda absoluta contra una espiritualidad c\u00f3smica m\u00e1s libre."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Nuevos Dioses es hijo de Darkseid pero fue criado en New Genesis?",o:["Mister Miracle", "Orion", "Lightray", "Metron"],a:1,exp:"Orion es hijo biol\u00f3gico de Darkseid, criado en New Genesis como parte de un pacto entre mundos.",extra:"Orion vive una tensi\u00f3n constante entre su naturaleza violenta heredada y los valores nobles de New Genesis. Esa contradicci\u00f3n lo convierte en uno de los Nuevos Dioses m\u00e1s dram\u00e1ticos."},
  {t:"m",q:"\u00bfQu\u00e9 escapista de los Nuevos Dioses es conocido como Mister Miracle?",o:["Scott Free", "Orion", "Metron", "Big Barda"],a:0,exp:"Scott Free es Mister Miracle, maestro escapista y uno de los Nuevos Dioses m\u00e1s queridos.",extra:"Mister Miracle mezcla aventura c\u00f3smica con una met\u00e1fora poderosa sobre escapar del trauma, el control y los sistemas opresivos. Su relaci\u00f3n con Big Barda es una de las m\u00e1s fuertes de DC."},
  {t:"m",q:"\u00bfQu\u00e9 hero\u00edna de Apokolips abandona a las Furias Femeninas y se une a Mister Miracle?",o:["Big Barda", "Granny Goodness", "Lashina", "Mad Harriet"],a:0,exp:"Big Barda fue entrenada en Apokolips como guerrera, pero termina rebel\u00e1ndose y formando una vida con Scott Free.",extra:"Barda es una de las guerreras m\u00e1s imponentes de DC. Su historia es de liberaci\u00f3n: alguien criada para servir a la tiran\u00eda que elige amor, libertad y hero\u00edsmo."},
  {t:"m",q:"\u00bfQu\u00e9 villana de Apokolips entrena brutalmente a soldados y Furias Femeninas?",o:["Granny Goodness", "Queen Bee", "Maxima", "Emerald Empress"],a:0,exp:"Granny Goodness entrena soldados de Apokolips mediante abuso, adoctrinamiento y crueldad.",extra:"Su nombre ir\u00f3nico es parte del horror del personaje. Granny convierte la idea de cuidado materno en una herramienta de control totalitario."},
  {t:"m",q:"\u00bfQu\u00e9 cuerpo policial intergal\u00e1ctico tiene su base en Oa?",o:["Green Lantern Corps", "Omega Men", "Darkstars", "L.E.G.I.O.N."],a:0,exp:"El Green Lantern Corps tiene su base en Oa, planeta de los Guardianes del Universo.",extra:"Oa funciona como centro administrativo y simb\u00f3lico del espectro verde de la voluntad. Desde all\u00ed los Lanterns patrullan sectores espaciales enteros."},
  {t:"m",q:"\u00bfQui\u00e9nes crearon el Green Lantern Corps?",o:["Los Guardianes del Universo", "Los Nuevos Dioses", "Los Se\u00f1ores del Orden", "Los Controladores"],a:0,exp:"Los Guardianes del Universo crearon el Green Lantern Corps para mantener el orden intergal\u00e1ctico.",extra:"Los Guardianes suelen ser sabios pero fr\u00edos, y muchas historias muestran que su deseo de orden puede producir errores enormes, como el fracaso con Sinestro o los Manhunters."},
  {t:"m",q:"\u00bfQu\u00e9 planeta natal est\u00e1 asociado con Sinestro?",o:["Korugar", "Oa", "Rann", "Tamaran"],a:0,exp:"Sinestro proviene de Korugar, mundo que gobern\u00f3 con m\u00e9todos autoritarios antes de su ca\u00edda.",extra:"La historia de Korugar explica la filosof\u00eda de Sinestro: cree que el miedo produce orden. Su tragedia es que empez\u00f3 como protector y termin\u00f3 como tirano."},
  {t:"m",q:"\u00bfQu\u00e9 cuerpo del espectro emocional usa anillos rojos alimentados por la ira?",o:["Red Lantern Corps", "Sinestro Corps", "Blue Lantern Corps", "Indigo Tribe"],a:0,exp:"Los Red Lanterns usan anillos rojos alimentados por la ira.",extra:"El Red Lantern Corps, liderado frecuentemente por Atrocitus, canaliza rabia y dolor. Sus miembros suelen ser v\u00edctimas transformadas en armas emocionales."},
  {t:"m",q:"\u00bfQu\u00e9 cuerpo de Lanterns est\u00e1 asociado con la esperanza?",o:["Blue Lantern Corps", "Orange Lantern Corps", "Black Lantern Corps", "Star Sapphires"],a:0,exp:"El Blue Lantern Corps est\u00e1 asociado con la esperanza.",extra:"Los Blue Lanterns son especialmente poderosos junto a los Green Lanterns, porque la esperanza puede fortalecer la voluntad. Su rol es m\u00e1s espiritual que policial."},
  {t:"m",q:"\u00bfQu\u00e9 entidad o cuerpo est\u00e1 asociado con la avaricia y el color naranja?",o:["Larfleeze", "Saint Walker", "Atrocitus", "Nekron"],a:0,exp:"Larfleeze es el portador principal del poder naranja de la avaricia.",extra:"A diferencia de otros cuerpos, el naranja suele concentrarse en Larfleeze porque la avaricia no comparte bien. Es una idea simple y muy elegante dentro del espectro emocional."},
  {t:"m",q:"\u00bfQu\u00e9 evento de DC est\u00e1 centrado en los Black Lanterns y la resurrecci\u00f3n de muertos?",o:["Blackest Night", "Infinite Crisis", "Final Crisis", "Zero Hour"],a:0,exp:"Blackest Night gira alrededor de los Black Lanterns, Nekron y h\u00e9roes o villanos muertos que regresan como amenazas.",extra:"Blackest Night convirti\u00f3 la historia emocional del universo DC en terror c\u00f3smico. Los muertos regresaban no como ellos mismos, sino como armas que explotaban v\u00ednculos afectivos."},
  {t:"m",q:"\u00bfQu\u00e9 velocista fue el Flash original de la Edad de Oro?",o:["Jay Garrick", "Barry Allen", "Wally West", "Bart Allen"],a:0,exp:"Jay Garrick fue el Flash original de la Edad de Oro de los c\u00f3mics.",extra:"Jay usa un casco met\u00e1lico inspirado en Mercurio y representa la primera generaci\u00f3n heroica de DC. Su existencia permite explorar legado, mentor\u00eda y mundos paralelos."},
  {t:"m",q:"\u00bfQu\u00e9 velocista fue Kid Flash antes de convertirse en Flash?",o:["Wally West", "Barry Allen", "Eobard Thawne", "Max Mercury"],a:0,exp:"Wally West comenz\u00f3 como Kid Flash y luego hered\u00f3 el manto de Flash.",extra:"Wally es uno de los mejores ejemplos de legado superheroico funcionando. Pas\u00f3 de sidekick a h\u00e9roe principal, desarrollando una relaci\u00f3n muy profunda con la Speed Force."},
  {t:"m",q:"\u00bfQu\u00e9 nieto de Barry Allen ha usado el nombre Impulse?",o:["Bart Allen", "Wallace West", "Jai West", "Don Allen"],a:0,exp:"Bart Allen, nieto de Barry Allen, comenz\u00f3 como Impulse.",extra:"Bart fue criado en circunstancias extra\u00f1as relacionadas con el futuro y la velocidad. Su personalidad impulsiva hac\u00eda literal su nombre heroico, aunque luego madur\u00f3 como Kid Flash y Flash."},
  {t:"m",q:"\u00bfQu\u00e9 villano telep\u00e1tico de Flash es un gorila superinteligente?",o:["Gorilla Grodd", "Monsieur Mallah", "Ultra-Humanite", "Solovar"],a:0,exp:"Gorilla Grodd es un gorila con poderes mentales y uno de los enemigos m\u00e1s famosos de Flash.",extra:"Grodd viene de Gorilla City y mezcla ciencia ficci\u00f3n, telepat\u00eda y ambici\u00f3n conquistadora. Es absurdo en concepto, pero genuinamente peligroso en ejecuci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Flash usa espejos y dimensiones reflectantes para cometer cr\u00edmenes?",o:["Mirror Master", "Weather Wizard", "Trickster", "Pied Piper"],a:0,exp:"Mirror Master usa tecnolog\u00eda de espejos para transportarse, atrapar enemigos y crear ilusiones.",extra:"Mirror Master funciona muy bien contra Flash porque su poder no consiste en correr m\u00e1s r\u00e1pido, sino en distorsionar espacio, percepci\u00f3n y rutas de escape."},
  {t:"m",q:"\u00bfQu\u00e9 miembro de los Rogues controla el clima con una varita tecnol\u00f3gica?",o:["Weather Wizard", "Captain Boomerang", "Heat Wave", "Top"],a:0,exp:"Weather Wizard usa una varita para manipular fen\u00f3menos clim\u00e1ticos.",extra:"Como muchos Rogues, Weather Wizard es un criminal con una herramienta muy espec\u00edfica pero extremadamente peligrosa. En grupo, estas habilidades obligan a Flash a pensar m\u00e1s all\u00e1 de la velocidad."},
  {t:"m",q:"\u00bfQu\u00e9 villano australiano suele usar b\u00fameranes como armas?",o:["Captain Boomerang", "Deadshot", "Merlyn", "Sportsmaster"],a:0,exp:"Captain Boomerang es un villano asociado tanto a Flash como al Suicide Squad.",extra:"Aunque puede sonar rid\u00edculo, Captain Boomerang ha sobrevivido d\u00e9cadas gracias a carisma, oportunismo y una especialidad visualmente memorable. Es uno de esos personajes DC que abrazan lo extra\u00f1o."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe adolescente de DC tiene poderes el\u00e9ctricos y vive en Dakota?",o:["Static", "Blue Beetle", "Damage", "Sideways"],a:0,exp:"Static, Virgil Hawkins, es un h\u00e9roe adolescente con poderes electromagn\u00e9ticos asociado a Dakota.",extra:"Static naci\u00f3 en Milestone Comics y luego se integr\u00f3 al universo DC. Su serie animada lo volvi\u00f3 especialmente querido por una generaci\u00f3n de fans."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe latino usa un escarabajo alien\u00edgena como armadura?",o:["Jaime Reyes", "Ted Kord", "Michael Carter", "Ryan Choi"],a:0,exp:"Jaime Reyes es Blue Beetle y usa un escarabajo alien\u00edgena que genera una armadura avanzada.",extra:"Jaime destaca porque combina vida familiar, adolescencia y tecnolog\u00eda c\u00f3smica. A diferencia de otros h\u00e9roes con identidades secretas aisladas, su familia suele ser parte importante de su historia."},
  {t:"m",q:"\u00bfQu\u00e9 versi\u00f3n cl\u00e1sica de Blue Beetle no ten\u00eda poderes, pero era inventor y h\u00e9roe tecnol\u00f3gico?",o:["Ted Kord", "Jaime Reyes", "Dan Garrett", "Ray Palmer"],a:0,exp:"Ted Kord fue Blue Beetle como inventor, acr\u00f3bata y h\u00e9roe tecnol\u00f3gico sin poderes propios.",extra:"Ted funciona como un h\u00e9roe ingenioso y humano, m\u00e1s cercano a Batman en recursos, pero con un tono m\u00e1s ligero. Su amistad con Booster Gold es una de las din\u00e1micas m\u00e1s queridas de DC."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe del futuro usa tecnolog\u00eda y fama como parte de su identidad?",o:["Booster Gold", "Animal Man", "Hourman", "Captain Atom"],a:0,exp:"Booster Gold es un h\u00e9roe del futuro que viaja al presente buscando fama, aunque con el tiempo demuestra verdadero hero\u00edsmo.",extra:"La gracia de Booster es que empieza como un oportunista y termina siendo mucho m\u00e1s noble de lo que parece. Muchas historias lo usan para explorar reputaci\u00f3n, sacrificio y segundas oportunidades."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe puede encogerse usando tecnolog\u00eda de enana blanca?",o:["Atom", "Plastic Man", "Elongated Man", "Mister Terrific"],a:0,exp:"The Atom, especialmente Ray Palmer, puede reducir su tama\u00f1o gracias a tecnolog\u00eda basada en materia de enana blanca.",extra:"Atom permite historias de ciencia ficci\u00f3n microsc\u00f3pica: viajes dentro de cuerpos, mundos diminutos y amenazas invisibles. Es uno de los cient\u00edficos h\u00e9roes cl\u00e1sicos de DC."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe detective y atleta es conocido por sus esferas T y su lema \u201cFair Play\u201d?",o:["Mister Terrific", "Question", "Guardian", "Wildcat"],a:0,exp:"Mister Terrific, Michael Holt, es un genio, atleta y h\u00e9roe tecnol\u00f3gico que usa esferas T.",extra:"Michael Holt es considerado uno de los hombres m\u00e1s inteligentes del universo DC. Su hero\u00edsmo nace de reconstruirse tras una p\u00e9rdida devastadora y encontrar prop\u00f3sito en ayudar a otros."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe sin rostro suele investigar conspiraciones bajo el nombre The Question?",o:["Vic Sage", "Ted Grant", "Ralph Dibny", "Carter Hall"],a:0,exp:"Vic Sage es The Question, un detective vigilante asociado a conspiraciones, filosof\u00eda y crimen urbano.",extra:"The Question se mueve en historias m\u00e1s paranoicas y noir. Su m\u00e1scara sin rasgos lo vuelve una imagen perfecta para alguien obsesionado con descubrir qu\u00e9 hay debajo de las apariencias."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe boxeador entren\u00f3 a varios justicieros y pertenece a la Sociedad de la Justicia?",o:["Wildcat", "Hourman", "Sandman", "Starman"],a:0,exp:"Wildcat, Ted Grant, es un boxeador y miembro cl\u00e1sico de la Sociedad de la Justicia.",extra:"Wildcat es importante porque ha entrenado a h\u00e9roes como Black Canary, Batman y Catwoman en distintas versiones. Representa la vieja escuela del hero\u00edsmo callejero."},
  {t:"m",q:"\u00bfQu\u00e9 equipo fue precursor hist\u00f3rico de la Liga de la Justicia en la Edad de Oro?",o:["Sociedad de la Justicia de Am\u00e9rica", "J\u00f3venes Titanes", "Outsiders", "Omega Men"],a:0,exp:"La Sociedad de la Justicia de Am\u00e9rica fue el gran equipo superheroico de la Edad de Oro de DC.",extra:"La JSA permite que DC trate el hero\u00edsmo como legado generacional. Sus miembros veteranos conectan guerras pasadas, familias heroicas y nuevas generaciones."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe arque\u00f3logo suele reencarnar junto a Hawkgirl o Hawkwoman?",o:["Hawkman", "Doctor Fate", "Adam Strange", "Red Tornado"],a:0,exp:"Hawkman, en muchas versiones, est\u00e1 ligado a ciclos de reencarnaci\u00f3n junto a su pareja.",extra:"Hawkman tiene una de las continuidades m\u00e1s complejas de DC, mezclando arqueolog\u00eda, Thanagar, Egipto antiguo, reencarnaci\u00f3n y ciencia ficci\u00f3n espacial."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe m\u00e1gico usa el Casco de Nabu?",o:["Doctor Fate", "Zatara", "Etrigan", "Phantom Stranger"],a:0,exp:"Doctor Fate obtiene gran parte de su poder del Casco de Nabu.",extra:"Doctor Fate representa el lado m\u00e1s c\u00f3smico y ordenado de la magia en DC. Usar el casco implica poder enorme, pero tambi\u00e9n perder parte de la autonom\u00eda ante Nabu."},
  {t:"m",q:"\u00bfQu\u00e9 demonio rimador est\u00e1 ligado al humano Jason Blood?",o:["Etrigan", "Trigon", "Neron", "Sabbac"],a:0,exp:"Etrigan es un demonio vinculado a Jason Blood, conocido por hablar en rimas en muchas historias.",extra:"Etrigan combina horror, fantas\u00eda art\u00farica y humor oscuro. Su v\u00ednculo con Jason Blood es tanto una maldici\u00f3n como una fuente de poder."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe de DC es un polic\u00eda espacial de Rann y pareja de Alanna?",o:["Adam Strange", "Captain Atom", "Space Ghost", "Starman"],a:0,exp:"Adam Strange es un h\u00e9roe humano transportado a Rann mediante el Rayo Zeta.",extra:"Adam Strange es ciencia ficci\u00f3n pulp cl\u00e1sica: un hombre com\u00fan convertido en defensor de un mundo alien\u00edgena, con aventuras de rayos, jetpacks y romance interplanetario."},
  {t:"m",q:"\u00bfQu\u00e9 planeta est\u00e1 hist\u00f3ricamente en guerra o tensi\u00f3n con Rann?",o:["Thanagar", "Oa", "Tamaran", "Colu"],a:0,exp:"Thanagar, mundo asociado a los hawkmen, ha estado en conflicto con Rann en varias historias.",extra:"El conflicto Rann-Thanagar permite a DC explorar guerras espaciales donde no todo se reduce a h\u00e9roes y villanos, sino a intereses pol\u00edticos, culturas y supervivencia."},
  {t:"m",q:"\u00bfQu\u00e9 villano mercenario es conocido como Deathstroke?",o:["Slade Wilson", "Floyd Lawton", "David Cain", "Ben Turner"],a:0,exp:"Deathstroke es Slade Wilson, un mercenario mejorado y uno de los combatientes m\u00e1s peligrosos de DC.",extra:"Deathstroke empez\u00f3 como enemigo de los Titanes y creci\u00f3 hasta convertirse en amenaza para muchos h\u00e9roes. Su mezcla de estrategia, fuerza y crueldad lo hace temible."},
  {t:"m",q:"\u00bfQu\u00e9 tirador experto del Suicide Squad es conocido como Deadshot?",o:["Floyd Lawton", "George Harkness", "Digger Harkness", "Rick Flag"],a:0,exp:"Deadshot es Floyd Lawton, un asesino experto famoso por su punter\u00eda casi perfecta.",extra:"Deadshot suele ser retratado como alguien autodestructivo, profesional y cansado. Su v\u00ednculo con su hija a\u00f1ade humanidad a un personaje que vive haciendo trabajos terribles."},
  {t:"m",q:"\u00bfQu\u00e9 personaje militar suele liderar al Suicide Squad en campo?",o:["Rick Flag", "Steve Trevor", "Sam Lane", "King Faraday"],a:0,exp:"Rick Flag suele ser el l\u00edder de campo del Suicide Squad.",extra:"Rick Flag funciona como contraste con Amanda Waller: ambos cumplen misiones oscuras, pero Flag suele cargar m\u00e1s directamente con el peso moral de mandar criminales a morir."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Shazam obtiene poderes al decir tambi\u00e9n una palabra m\u00e1gica, pero con origen oscuro?",o:["Black Adam", "Sivana", "Mister Mind", "Ibac"],a:0,exp:"Black Adam obtiene poderes m\u00e1gicos similares a Shazam, aunque suele usarlos de forma mucho m\u00e1s implacable.",extra:"Black Adam es uno de los grandes antih\u00e9roes de DC. Su relaci\u00f3n con Kahndaq, la p\u00e9rdida y el poder absoluto lo vuelve m\u00e1s complejo que un simple doble malvado de Shazam."},
];

export default dcQuestions;
